//! The purpose of this binary is to perform a single run of the primitive under test so that
//! its peak memory usage can be measured with:
//!
//!     valgrind --tool=massif --heap=no --stacks=yes -- target/release/bench_mlkem_mem_usage > /dev/null
//!
//!     ms_print massif.out.835000
//!
//! or, shoved all into one line:
//!
//!     clear; clear; valgrind --tool=massif --heap=no --stacks=yes -- target/release/bench_mlkem_mem_usage > /dev/null; ms_print massif.out.*; rm massif.out.*
//!
//!
//! To measure code size, Claude suggests:
//! 
//!    To see code size separately: size ./your_binary or readelf -S ./your_binary (look at .text).
//!
//! Make sure you build in release mode!
//!
//! Note: I'm using print!() to force the compiler not to optimize away the actual code.
//! I'm printing the important stuff for benchmarking to stderr so that I can pipe the junk to /dev/null
//! (I'm not doing it the other way because /usr/bin/time prints its useful stuff to stderr as well)
//!
//! Main is at the bottom, controls which this was actually run.

#![allow(dead_code)]
#![allow(unused_imports)]

use bouncycastle::core::key_material::{KeyMaterial512, KeyType};
use bouncycastle::core::traits::{KEMDecapsulator, KEMEncapsulator, KEMPublicKey};
use bouncycastle::mlkem::mlkem::{MLKEMTrait};
use bouncycastle::mlkem::{MLKEM1024_CT_LEN, MLKEM1024_PK_LEN, MLKEM512_CT_LEN, MLKEM512_PK_LEN, MLKEM768_CT_LEN, MLKEM768_PK_LEN};

/// This exists so I can use /usr/bin/time to measure the base memory footprint of the cargo bench harness
fn bench_do_nothing() {
    eprintln!("DoNothing");

    print!("{}", 1 + 1);
}

/// This prints the in-memory size of all the public and private key structs
fn print_struct_sizes() {
    use core::mem::size_of;
    use bouncycastle::mlkem;
    use bouncycastle::mlkem_lowmemory;


    println!("\nML-KEM-512");
    println!("size_of<mlkem::MLKEM512PublicKey>: {}", size_of::<mlkem::MLKEM512PublicKey>());
    println!("size_of<mlkem::MLKEM512PublicKeyExpanded>: {}", size_of::<mlkem::MLKEM512PublicKeyExpanded>());
    println!("size_of<mlkem::MLKEM512PrivateKey>: {}", size_of::<mlkem::MLKEM512PrivateKey>());
    println!("size_of<mlkem::MLKEM512PrivateKeyExpanded>: {}", size_of::<mlkem::MLKEM512PrivateKeyExpanded>());


    println!("\nML-KEM-768");
    println!("size_of<mlkem::MLKEM768PublicKey>: {}", size_of::<mlkem::MLKEM768PublicKey>());
    println!("size_of<mlkem::MLKEM768PublicKeyExpanded>: {}", size_of::<mlkem::MLKEM768PublicKeyExpanded>());
    println!("size_of<mlkem::MLKEM768PrivateKey>: {}", size_of::<mlkem::MLKEM768PrivateKey>());
    println!("size_of<mlkem::MLKEM768PrivateKeyExpanded>: {}", size_of::<mlkem::MLKEM768PrivateKeyExpanded>());

    println!("\nML-KEM-1024");
    println!("size_of<mlkem::MLKEM1024PublicKey>: {}", size_of::<mlkem::MLKEM1024PublicKey>());
    println!("size_of<mlkem::MLKEM1024PublicKeyExpanded>: {}", size_of::<mlkem::MLKEM1024PublicKeyExpanded>());
    println!("size_of<mlkem::MLKEM1024PrivateKey>: {}", size_of::<mlkem::MLKEM1024PrivateKey>());
    println!("size_of<mlkem::MLKEM1024PrivateKeyExpanded>: {}", size_of::<mlkem::MLKEM1024PrivateKeyExpanded>());

    println!("\n\nlowmemory");

    println!("\nML-KEM-512_lowmemory");
    println!("size_of<mlkem_lowmemory::MLKEM512PublicKey>: {}", size_of::<mlkem_lowmemory::MLKEM512PublicKey>());
    println!("size_of<mlkem_lowmemory::MLKEM512PrivateKey>: {}", size_of::<mlkem_lowmemory::MLKEM512PrivateKey>());


    println!("\nML-KEM-768_lowmemory");
    println!("size_of<mlkem_lowmemory::MLKEM768PublicKey>: {}", size_of::<mlkem_lowmemory::MLKEM768PublicKey>());
    println!("size_of<mlkem_lowmemory::MLKEM768PrivateKey>: {}", size_of::<mlkem_lowmemory::MLKEM768PrivateKey>());

    println!("\nML-KEM-1024_lowmemory");
    println!("size_of<mlkem_lowmemory::MLKEM1024PublicKey>: {}", size_of::<mlkem_lowmemory::MLKEM1024PublicKey>());
    println!("size_of<mlkem_lowmemory::MLKEM1024PrivateKey>: {}", size_of::<mlkem_lowmemory::MLKEM1024PrivateKey>());
}

fn bench_mlkem512_keygen() {
    use bouncycastle::mlkem::{MLKEM512};

    eprintln!("MLKEM512/KeyGen");

    let seed = KeyMaterial512::from_bytes_as_type(
        &[0x00,0x01,0x02,0x03,0x04,0x05,0x06,0x07,0x08,0x09,0x0a,0x0b,0x0c,0x0d,0x0e,0x0f,0x10,0x11,0x12,0x13,0x14,0x15,0x16,0x17,0x18,0x19,0x1a,0x1b,0x1c,0x1d,0x1e,0x1f,0x00,0x01,0x02,0x03,0x04,0x05,0x06,0x07,0x08,0x09,0x0a,0x0b,0x0c,0x0d,0x0e,0x0f,0x10,0x11,0x12,0x13,0x14,0x15,0x16,0x17,0x18,0x19,0x1a,0x1b,0x1c,0x1d,0x1e,0x1f],
        KeyType::Seed,
    ).unwrap();

    let (pk, _sk) = MLKEM512::keygen_from_seed(&seed).unwrap();
    println!("{:x?}", pk.encode());
}

